public ClassDescription defaultCaption()
{
    return "Create multithreading tasks";
}

public static HDG_SysMultiThreadCreateTasksController construct(SysOperationExecutionMode _executionMode = SysOperationExecutionMode::Synchronous)
{
    HDG_SysMultiThreadCreateTasksController controller = new HDG_SysMultiThreadCreateTasksController();
    controller.parmExecutionMode(_executionMode);
    return controller;
}

public static void main(Args _args)
{
    HDG_SysMultiThreadCreateTasksController multiThreadingCreateTasksController = HDG_SysMultiThreadCreateTasksController::construct();

    HDG_SysMultiThreadCreateTasksContract contract = multiThreadingCreateTasksController.getDataContractObject() as HDG_SysMultiThreadCreateTasksContract;
    contract.parmNumberOfThreads(4);

    multiThreadingCreateTasksController.parmArgs(_args);
    multiThreadingCreateTasksController.startOperation();
}
